"""Request model for the preferences SubApp.

Kept in a dedicated models.py (like every other domain) so the generated SDK can
vendor it verbatim. NOT an event: it carries no IngestMeta (ts / submission_id).
Identity is resolved from the bearer token, so only the preference travels in the
body.
"""

from pydantic import BaseModel


class OptOutWrite(BaseModel):
    opted_out: bool
